import React, { useState, useEffect } from 'react';
import AddHabitForm from './components/AddHabitForm';
import HabitList from './components/HabitList';

function App() {
  const [habits, setHabits] = useState([]);

  useEffect(() => {
    const storedHabits = localStorage.getItem('habits');
    if (storedHabits) {
      setHabits(JSON.parse(storedHabits));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('habits', JSON.stringify(habits));
  }, [habits]);

  const deleteHabit = (id) => {
    setHabits(habits.filter(h => h.id !== id));
  };

  const editHabit = (id, newName) => {
    setHabits(habits.map(h => h.id === id ? { ...h, name: newName } : h));
  };

  const toggleCompletion = (id, date, intensity) => {
    setHabits(habits.map(habit => {
      if (habit.id === id) {
        const completions = { ...habit.completions };
        completions[date] = intensity;
        return { ...habit, completions };
      }
      return habit;
    }));
  };

  const totalScore = habits.reduce((total, habit) => {
    return total + Object.values(habit.completions).reduce((sum, val) => sum + (val || 0), 0);
  }, 0);

  return (
    <div className="min-h-screen bg-gray-100 p-4">
      <h1 className="text-3xl font-bold text-center mb-8">Habit Tracker</h1>
      <div className="text-center mb-4">Total Score: {totalScore}</div>
      <AddHabitForm onAdd={addHabit} />
      <HabitList habits={habits} onToggle={toggleCompletion} />
    </div>
  );
}

export default App;
